#include<cstdio>
#include<vector>
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline bool Get(){char c;do c=getchar();while(c!='0'&&c!='1');return c=='1';}
const int N=21; int n,K;std::vector< std::vector<int> > dp[N][N],nxt[N],len[N];
inline void print(int L,int S){putchar('(');for(int i=L-1;~i;--i)putchar(S>>i&1?'1':'0');putchar(')');}
int main()
{
	n=read();K=read();
	for(int i=0;i<=n;++i)
	{
		for(int j=0;i+j<=n;++j)
		{
			dp[i][j].resize(1<<i);
			for(int k=0;k<(1<<i);++k)dp[i][j][k].resize(1<<j);
		}
		for(int j=0;j<(1<<i);++j)dp[0][i][0][j]=Get();
	}
	for(int i=0;i<=n;++i)
	{
		nxt[i].resize(1<<i);len[i].resize(1<<i);
		for(int j=0;j<1<<i;++j)nxt[i][j].resize(2),len[i][j].resize(2);
	}
	for(int L=0;L<=n;++L)
	{
		for(int S=0;S<(1<<L);++S)
		{
			len[L][S][0]=len[L][S][1]=-1;
			for(int i=L-1;~i;--i)
			{
				if(S>>i&1)
				{
					nxt[L][S][1]=S&((1<<i)-1);
					len[L][S][1]=i;break;
				}
			}
			for(int i=L-1;~i;--i)
			{
				if(!(S>>i&1))
				{
					nxt[L][S][0]=S&((1<<i)-1);
					len[L][S][0]=i;break;
				}
			}
		}
	}
	for(int i=0;i<n;++i)//S长度 
	{
		for(int j=0;i+j<=n;++j)//T长度 
		{
			//dp[i][j][S][T] --> dp[i+1][len(nxt[j][T][0/1])][S+'0/1'][nxt[j][T][0/1]]
			//				 --> dp[i][0][S][0]
			for(int S=0;S<(1<<i);++S)
			{
				for(int T=0;T<(1<<j);++T)
				{
					int w=dp[i][j][S][T];
					if(~len[j][T][0])
					{
						dp[i+1][len[j][T][0]][S<<1][nxt[j][T][0]]+=w;
//						print(i,S);print(j,T);printf("-->");print(i+1,S<<1);print(len[j][T][0],nxt[j][T][0]);
//						printf(":: %d %d(case 2)\n",w,dp[i+1][len[j][T][0]][S<<1][nxt[j][T][0]]);
					}
					if(~len[j][T][1])
					{
						dp[i+1][len[j][T][1]][S<<1|1][nxt[j][T][1]]+=w;
//						print(i,S);print(j,T);printf("-->");print(i+1,S<<1|1);print(len[j][T][1],nxt[j][T][1]);
//						printf(":: %d %d(case 2)\n",w,dp[i+1][len[j][T][1]][S<<1|1][nxt[j][T][1]]);
					}
					if(j!=0)
					{
						dp[i][0][S][0]+=w;
//						print(i,S);print(j,T);printf("-->");print(i,S);print(0,0);
//						printf(":: %d %d(case 3)\n",w,dp[i][0][S][0]);
					}
				}
			}
		}
	}
	for(int i=n;i;--i)
	{
		for(int S=0;S<(1<<i);++S)if(dp[i][0][S][0]>=K)
		{
			for(int j=i-1;~j;--j)putchar(S>>j&1?'1':'0');puts("");
//			printf("QAQ :: %d\n",dp[i][0][S][0]);
			return 0;
		}
	}
	puts("");return 0;
}
